// Validar datos de entrada
const data = $input.first().json.body;

if (!data.user_id || !data.image_base64) {
  throw new Error('Faltan campos requeridos: user_id, image_base64');
}

return [{
  json: {
    user_id: data.user_id,
    image_base64: data.image_base64,
    timestamp: new Date().toISOString()
  }
}];

// Convertir base64 a Buffer para Google Vision
const imageBuffer = Buffer.from($node["Validar Input"].json.image_base64, 'base64');

return [{
  json: {
    ...$node["Validar Input"].json,
    image_buffer: imageBuffer.toString('base64'),
    storage_path: $node["Subir a Supabase Storage"].json.path
  }
}];

// Parsear respuesta de Google Vision
const response = $input.first().json;
const text = response.responses[0].fullTextAnnotation.text;

// Funciones de extracción
function extractAmount(text) {
  // Buscar montos en formato MXN o USD
  const patterns = [
    /\$\s?([\d,]+\.\d{2})/g,
    /MXN\s?([\d,]+\.\d{2})/g,
    /USD\s?([\d,]+\.\d{2})/g,
    /TOTAL[:\s]*([\d,]+\.\d{2})/g,
    /IMPORTE[:\s]*([\d,]+\.\d{2})/g
  ];

  let amounts = [];
  for (const pattern of patterns) {
    let match;
    while ((match = pattern.exec(text)) !== null) {
      const amount = parseFloat(match[1].replace(/,/g, ''));
      if (amount > 0 && amount < 1000000) {
        amounts.push(amount);
      }
    }
  }

  // Retornar el monto más común o el último encontrado
  return amounts.length > 0 ? Math.max(...amounts) : null;
}

function extractDate(text) {
  const patterns = [
    /(\d{1,2})[\/\-](\d{1,2})[\/\-](\d{2,4})/,
    /(\d{4})[\/\-](\d{1,2})[\/\-](\d{1,2})/,
    /(\d{1,2})\s+(ene|feb|mar|abr|may|jun|jul|ago|sep|oct|nov|dic)[a-z]*\s+(\d{2,4})/i
  ];

  for (const pattern of patterns) {
    const match = text.match(pattern);
    if (match) {
      let date;
      if (pattern.source.includes('ene|feb')) {
        // Formato con meses en español
        const months = {
          'ene': 0, 'feb': 1, 'mar': 2, 'abr': 3, 'may': 4, 'jun': 5,
          'jul': 6, 'ago': 7, 'sep': 8, 'oct': 9, 'nov': 10, 'dic': 11
        };
        const day = parseInt(match[1]);
        const month = months[match[2].toLowerCase()];
        const year = parseInt(match[3]);
        date = new Date(year, month, day);
      } else {
        date = new Date(match[0]);
      }

      if (!isNaN(date.getTime())) {
        return date.toISOString().split('T')[0];
      }
    }
  }
  return null;
}

function extractProvider(text) {
  const lines = text.split('\n').filter(line => line.trim().length > 3);
  // Las primeras líneas suelen ser el proveedor
  for (let i = 0; i < Math.min(5, lines.length); i++) {
    const line = lines[i].trim();
    if (line.length > 3 && line.length < 100 && !line.match(/^\d/)) {
      return line;
    }
  }
  return 'Proveedor no identificado';
}

const extractedData = {
  monto: extractAmount(text),
  fecha_factura: extractDate(text),
  proveedor: extractProvider(text),
  concepto_ocr: text
};

return [{
  json: {
    ...$node["Preparar OCR"].json,
    ...extractedData
  }
}];

// Preparar respuesta para el frontend
const data = $input.first().json;
const supabaseData = $node["Insertar en Supabase"].json;

return [{
  json: {
    success: true,
    factura_id: supabaseData[0].id,
    extracted_data: {
      monto: data.monto,
      fecha_factura: data.fecha_factura,
      proveedor: data.proveedor
    },
    storage_url: data.storage_path,
    message: 'Factura procesada exitosamente'
  }
}];
